def _case_matches_partition_rule(case: dict, case_id: str, rule: dict) -> bool:
    rule_case_ids = rule.get("case_ids", [])
    if isinstance(rule_case_ids, list) and rule_case_ids and case_id not in {str(item) for item in rule_case_ids}:
        return False
    seq_name = str(case.get("seq_name"))
    if rule.get("seq_name") and str(rule.get("seq_name")) != seq_name:
        return False
    target_camera = str(case.get("target_camera"))
    if rule.get("target_camera") and str(rule.get("target_camera")) != target_camera:
        return False
    frame_id = int(case.get("frame_id"))
    if rule.get("frame_min") is not None and frame_id < int(rule.get("frame_min")):
        return False
    if rule.get("frame_max") is not None and frame_id > int(rule.get("frame_max")):
        return False
    return True


def _resolve_case_proxy_config(case: dict, case_id: str, proxy_config: dict) -> tuple[dict, dict]:
    resolved = dict(proxy_config)
    applied_rules = []
    for raw_rule in proxy_config.get("partition_rules", []):
        if not isinstance(raw_rule, dict):
            continue
        if not _case_matches_partition_rule(case, case_id, raw_rule):
            continue
        override = raw_rule.get("proxy_config", {})
        if not isinstance(override, dict):
            override = {}
        resolved.update(override)
        applied_rules.append(
            {
                "rule_id": str(raw_rule.get("rule_id", f"rule_{len(applied_rules)}")),
                "target_camera": raw_rule.get("target_camera"),
                "frame_min": raw_rule.get("frame_min"),
                "frame_max": raw_rule.get("frame_max"),
                "case_ids": list(raw_rule.get("case_ids", [])) if isinstance(raw_rule.get("case_ids", []), list) else [],
            }
        )
    resolved["partition_rules"] = list(proxy_config.get("partition_rules", []))
    return resolved, {"applied_partition_rules": applied_rules}


def _select_cases(manifest: dict, case_set: str) -> list[dict]:
    if case_set == "all":
        rows = []
        for key in ("hero_cases", "benchmark_cases", "cases"):
            rows.extend(list(manifest.get(key, [])))
        return rows
    return list(manifest.get(case_set, []))


def _resolve_variants(raw_value: str) -> list[str]:
    text = str(raw_value or "").strip()
    if not text or text == "default":
        return list(DEFAULT_VARIANTS)
    if text == "none":
        return []
    if text == "default_plus_side":
        return list(DEFAULT_VARIANTS) + list(SIDE_VARIANTS)
    return [item.strip() for item in text.split(",") if item.strip()]


def _load_target_mask(seq_dir: Path, camera_name: str, frame_id: int, out_hw: tuple[int, int], mask_source: str) -> np.ndarray:
    if mask_source == "none":
        return np.ones(out_hw, dtype=bool)
    mask_path = seq_dir / mask_source / camera_name / f"{int(frame_id):06d}.png"
    mask = Image.open(mask_path).convert("L").resize((int(out_hw[1]), int(out_hw[0])), Image.Resampling.NEAREST)
    return np.asarray(mask, dtype=np.uint8) > 0


def _gaussian_kernel(channels: int, device: torch.device, dtype: torch.dtype, ksize: int = 11, sigma: float = 1.5) -> torch.Tensor:
    coords = torch.arange(ksize, device=device, dtype=dtype) - (ksize - 1) / 2.0
    values = torch.exp(-(coords**2) / (2 * sigma * sigma))
    values = values / values.sum()
    kernel_2d = (values[:, None] * values[None, :]).unsqueeze(0).unsqueeze(0)
    return kernel_2d.repeat(channels, 1, 1, 1)


def _ssim_rgb(pred01: np.ndarray, tgt01: np.ndarray) -> float:
    pred = torch.from_numpy(pred01.transpose(2, 0, 1)).unsqueeze(0).float()
    tgt = torch.from_numpy(tgt01.transpose(2, 0, 1)).unsqueeze(0).float()
    c1 = 0.01**2
    c2 = 0.03**2
    kernel = _gaussian_kernel(3, pred.device, pred.dtype)

    def filt(x: torch.Tensor) -> torch.Tensor:
        return F.conv2d(x, kernel, padding=5, groups=3)

    mu_x = filt(pred)
    mu_y = filt(tgt)
    mu_x2 = mu_x * mu_x
    mu_y2 = mu_y * mu_y
    mu_xy = mu_x * mu_y
    sigma_x2 = filt(pred * pred) - mu_x2
    sigma_y2 = filt(tgt * tgt) - mu_y2
    sigma_xy = filt(pred * tgt) - mu_xy
    ssim_map = ((2 * mu_xy + c1) * (2 * sigma_xy + c2)) / (
        (mu_x2 + mu_y2 + c1) * (sigma_x2 + sigma_y2 + c2) + 1e-8
    )
    return float(ssim_map.mean().item())


def _masked_metrics(pred01: np.ndarray, tgt01: np.ndarray, mask_hw: np.ndarray) -> dict:
    mask = np.asarray(mask_hw, dtype=np.float32)[..., None]
    denom = max(float(mask.sum() * 3.0), 1.0)
    abs_err = np.abs(pred01 - tgt01) * mask
    mse = float((((pred01 - tgt01) ** 2) * mask).sum() / denom)
    pred_masked = pred01 * mask
    tgt_masked = tgt01 * mask
    return {
        "l1": float(abs_err.sum() / denom),
        "psnr": float(-10.0 * math.log10(max(mse, 1e-8))),
        "ssim": _ssim_rgb(pred_masked, tgt_masked),
        "pixel_count": int(mask_hw.sum()),
    }


def _clamp_image(image01: np.ndarray) -> np.ndarray:
    return np.clip(np.asarray(image01, dtype=np.float32), 0.0, 1.0)


def _visible_mass_ratio(image01: np.ndarray, fg_mask: np.ndarray) -> float:
    image01 = np.asarray(image01, dtype=np.float32)
    fg_mask = np.asarray(fg_mask, dtype=bool)
    if int(fg_mask.sum()) <= 0:
        return 0.0
    denom = max(float(image01.max()) * 3.0 * max(int(fg_mask.sum()), 1), 1e-8)
    return float(image01[fg_mask].sum() / denom)


def _apply_variant(depth_render: np.ndarray, weight01: np.ndarray, fg_mask: np.ndarray, variant_name: str) -> np.ndarray:
    depth_render = _clamp_image(depth_render)
    weight01 = np.asarray(weight01, dtype=np.float32)
    fg_mask = np.asarray(fg_mask, dtype=bool)
    if variant_name == "guided_blur":
        blur = cv2.GaussianBlur(to_uint8(depth_render), (0, 0), 1.2).astype(np.float32) / 255.0
        alpha = np.clip((weight01 - 0.08) / 0.25, 0.0, 1.0)[..., None]
        return _clamp_image(depth_render * alpha + blur * (1.0 - alpha))

    hole = (weight01 < 0.03).astype(np.uint8) * 255
    inpaint = cv2.inpaint(to_uint8(depth_render), hole, 3, cv2.INPAINT_TELEA).astype(np.float32) / 255.0
    if variant_name == "mask_hole_fill":
        mask_hole = ((weight01 < 0.05) & fg_mask).astype(np.float32)[..., None]
        return _clamp_image(depth_render * (1.0 - mask_hole) + inpaint * mask_hole)

    if variant_name == "mask_hole_fill_plus_guided":
        blur = cv2.GaussianBlur(to_uint8(depth_render), (0, 0), 1.2).astype(np.float32) / 255.0
        alpha = np.clip((weight01 - 0.08) / 0.25, 0.0, 1.0)[..., None]
        guided = depth_render * alpha + blur * (1.0 - alpha)
        mask_hole = ((weight01 < 0.05) & fg_mask).astype(np.float32)[..., None]
        return _clamp_image(guided * (1.0 - mask_hole) + inpaint * mask_hole)

    if variant_name == "mask_hole_fill_plus_guided_strong":
        blur = cv2.GaussianBlur(to_uint8(depth_render), (0, 0), 1.6).astype(np.float32) / 255.0
        alpha = np.clip((weight01 - 0.1) / 0.28, 0.0, 1.0)[..., None]
        guided = depth_render * alpha + blur * (1.0 - alpha)
        mask_hole = ((weight01 < 0.07) & fg_mask).astype(np.float32)[..., None]
        return _clamp_image(guided * (1.0 - mask_hole) + inpaint * mask_hole)

    if variant_name == "mask_hole_fill_plus_guided_soft":
        mask_hole = ((np.clip(0.12 - weight01, 0.0, 0.12) / 0.12) * fg_mask.astype(np.float32))[..., None]
        blur = cv2.GaussianBlur(to_uint8(inpaint), (0, 0), 0.8).astype(np.float32) / 255.0
        soft_inpaint = inpaint * 0.7 + blur * 0.3
        return _clamp_image(depth_render * (1.0 - mask_hole) + soft_inpaint * mask_hole)

    raise ValueError(f"Unsupported variant: {variant_name}")


def _save_rgb(path: Path, image01: np.ndarray) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    Image.fromarray(to_uint8(image01)).save(_native_io_path(path))


def _save_gray(path: Path, image01: np.ndarray) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    gray = np.clip(np.asarray(image01, dtype=np.float32) * 255.0, 0.0, 255.0).astype(np.uint8)
    Image.fromarray(gray, mode="L").save(_native_io_path(path))


def _native_io_path(path: Path) -> str:
    resolved = str(path.resolve())
    if os.name == "nt" and len(resolved) >= 240 and not resolved.startswith("\\\\?\\"):
        if resolved.startswith("\\\\"):
            return "\\\\?\\UNC\\" + resolved[2:]
        return "\\\\?\\" + resolved
    return resolved


def _path_safe_variant_token(name: str, max_len: int = 72) -> str:
    name = str(name)
    if len(name) <= max_len:
        return name
    digest = hashlib.sha1(name.encode("utf-8")).hexdigest()[:12]
    keep = max(16, max_len - len(digest) - 1)
    return f"{name[:keep]}_{digest}"


def _apply_sim3_points_float32(
    points: np.ndarray,
    scale: float | np.ndarray,
    rotation: np.ndarray,
    translation: np.ndarray,
) -> np.ndarray:
    points32 = np.asarray(points, dtype=np.float32)
    rotation32 = np.asarray(rotation, dtype=np.float32)
    translation32 = np.asarray(translation, dtype=np.float32)
    aligned = points32 @ rotation32.T
    aligned *= np.float32(scale)
    aligned += translation32
    return aligned.astype(np.float32, copy=False)


def save_json(path: Path, payload) -> None:
    path = Path(path)
    path.parent.mkdir(parents=True, exist_ok=True)
    with open(_native_io_path(path), "w", encoding="utf-8") as handle:
        json.dump(payload, handle, indent=2, ensure_ascii=False)


def _write_text(path: Path, text: str) -> None:
    path = Path(path)
    path.parent.mkdir(parents=True, exist_ok=True)
    with open(_native_io_path(path), "w", encoding="utf-8") as handle:
        handle.write(text)


def _json_safe(value):
    if isinstance(value, np.generic):
        return value.item()
    if isinstance(value, np.ndarray):
        return value.tolist()
    if isinstance(value, dict):
        return {str(key): _json_safe(item) for key, item in value.items()}
    if isinstance(value, (list, tuple)):
        return [_json_safe(item) for item in value]
    return value


def _build_bottom_band_mask(mask_hw: np.ndarray, bottom_band_ratio: float) -> np.ndarray:
    bottom_band_ratio = float(max(0.0, min(0.95, bottom_band_ratio)))
    bottom = np.zeros_like(mask_hw, dtype=bool)
    if bottom_band_ratio <= 0.0:
        return bottom
    cutoff = int(mask_hw.shape[0] * (1.0 - bottom_band_ratio))
    if cutoff < mask_hw.shape[0]:
        bottom[cutoff:, :] = True
    return bottom


def _apply_heatmap(values01: np.ndarray) -> np.ndarray:
    gray = np.clip(np.asarray(values01, dtype=np.float32) * 255.0, 0.0, 255.0).astype(np.uint8)
    heat = cv2.applyColorMap(gray, cv2.COLORMAP_TURBO)
    return cv2.cvtColor(heat, cv2.COLOR_BGR2RGB)


def _visible_rgb_mask(image01: np.ndarray, *, threshold: float = 0.05) -> np.ndarray:
    image01 = np.asarray(image01, dtype=np.float32)
    if image01.ndim != 3 or image01.shape[2] != 3:
        raise ValueError(f"expected HxWx3 image, got shape={image01.shape}")
    return np.max(image01, axis=2) > float(threshold)


def _normalize_support_weight(raw_weight: np.ndarray) -> np.ndarray:
    raw_weight = np.clip(np.asarray(raw_weight, dtype=np.float32), 0.0, None)
    hit = raw_weight > 0.0
    if not np.any(hit):
        return np.zeros_like(raw_weight, dtype=np.float32)
    p99 = float(np.percentile(raw_weight[hit], 99.0))
    denom = max(p99, 1e-8)
    return np.clip(raw_weight / denom, 0.0, 1.0).astype(np.float32)


def _render_forward_splat_with_raw(
    *,
    world_points_s_hw3: np.ndarray,
    world_conf_s_hw: np.ndarray,
    src_rgb_s_hw3: np.ndarray,
    tgt_extrinsic_3x4: np.ndarray,
    tgt_intrinsic_3x3: np.ndarray,
    out_hw: tuple[int, int],
    z_eps: float,
    min_conf: float,
    z_tolerance: float,
    max_points: int,
) -> dict:
    render = render_forward_splat(
        world_points_s_hw3=world_points_s_hw3,
        world_conf_s_hw=world_conf_s_hw,
        src_rgb_s_hw3=src_rgb_s_hw3,
        tgt_extrinsic_3x4=tgt_extrinsic_3x4,
        tgt_intrinsic_3x3=tgt_intrinsic_3x3,
        out_hw=out_hw,
        z_eps=z_eps,
        min_conf=min_conf,
        z_tolerance=z_tolerance,
        max_points=max_points,
    )

    height, width = int(out_hw[0]), int(out_hw[1])
    points = np.asarray(world_points_s_hw3, dtype=np.float64).reshape(-1, 3)
    conf = np.asarray(world_conf_s_hw, dtype=np.float64).reshape(-1)
    finite = np.isfinite(points).all(axis=-1) & np.isfinite(conf) & (conf >= float(min_conf))
    candidate_indices = np.flatnonzero(finite)
    if candidate_indices.size == 0:
        render["raw_weight"] = np.zeros((height, width), dtype=np.float32)
        return render

    if candidate_indices.size > int(max_points):
        candidate_conf = conf[candidate_indices]
        top_local = np.argpartition(candidate_conf, -int(max_points))[-int(max_points):]
        candidate_indices = candidate_indices[top_local]

    points = points[candidate_indices]
    conf = conf[candidate_indices]

    rotation = np.asarray(tgt_extrinsic_3x4[:3, :3], dtype=np.float64)
    translation = np.asarray(tgt_extrinsic_3x4[:3, 3], dtype=np.float64)
    cam = points @ rotation.T + translation[None, :]
    z = cam[:, 2]
    x = cam[:, 0] / np.maximum(z, 1e-12)
    y = cam[:, 1] / np.maximum(z, 1e-12)
    fx = float(tgt_intrinsic_3x3[0, 0])
    fy = float(tgt_intrinsic_3x3[1, 1])
    cx = float(tgt_intrinsic_3x3[0, 2])
    cy = float(tgt_intrinsic_3x3[1, 2])
    u = fx * x + cx
    v = fy * y + cy
    xi = np.rint(u).astype(np.int64)
    yi = np.rint(v).astype(np.int64)

    valid = np.isfinite(u) & np.isfinite(v) & np.isfinite(z)
    valid &= z > float(z_eps)
    valid &= xi >= 0
    valid &= yi >= 0
    valid &= xi < width
    valid &= yi < height
    if not np.any(valid):
        render["raw_weight"] = np.zeros((height, width), dtype=np.float32)
        return render

    pix = yi[valid] * width + xi[valid]
    z_valid = z[valid]
    conf_valid = conf[valid]

    order = np.lexsort((z_valid, pix))
    pix_sorted = pix[order]
    z_sorted = z_valid[order]
    conf_sorted = conf_valid[order]

    _, start_idx = np.unique(pix_sorted, return_index=True)
    counts = np.diff(np.concatenate([start_idx, np.array([pix_sorted.size])]))
    z_min = z_sorted[start_idx]
    z_min_rep = np.repeat(z_min, counts)
    keep = z_sorted <= (z_min_rep + float(z_tolerance))

    pix_kept = pix_sorted[keep]
    conf_kept = conf_sorted[keep]
    pixel_count = int(height * width)
    sum_w = np.bincount(pix_kept, weights=conf_kept, minlength=pixel_count).astype(np.float64)
    render["raw_weight"] = sum_w.reshape(height, width).astype(np.float32)
    return render


def _count_profile_peaks(profile: np.ndarray, *, min_rel_height: float = 0.35) -> int:
    profile = np.asarray(profile, dtype=np.float32).reshape(-1)
    if profile.size < 3:
        return 0
    peak_threshold = float(profile.max()) * float(min_rel_height)
    if peak_threshold <= 0.0:
        return 0
    peak_count = 0
    for idx in range(1, profile.size - 1):
        center = float(profile[idx])
        if center < peak_threshold:
            continue
        if center >= float(profile[idx - 1]) and center >= float(profile[idx + 1]):
            peak_count += 1
    return int(peak_count)


def _connected_component_ratio(binary_mask: np.ndarray) -> tuple[int, float]:
    binary_mask = np.asarray(binary_mask, dtype=np.uint8)
    component_count, component_labels = cv2.connectedComponents(binary_mask, connectivity=8)
    fg_connected_components = max(int(component_count) - 1, 0)
    if fg_connected_components <= 0:
        return 0, 0.0
    component_areas = [int((component_labels == label).sum()) for label in range(1, component_count)]
    largest_area = max(component_areas) if component_areas else 0
    ratio = float(largest_area / max(int(binary_mask.sum()), 1))
    return fg_connected_components, ratio


def _connected_component_stats(binary_mask: np.ndarray) -> dict:
    binary_mask = np.asarray(binary_mask, dtype=np.uint8)
    component_count, component_labels = cv2.connectedComponents(binary_mask, connectivity=8)
    fg_connected_components = max(int(component_count) - 1, 0)
    total_area = max(int(binary_mask.sum()), 1)
    if fg_connected_components <= 0:
        zero_mask = np.zeros_like(binary_mask, dtype=bool)
        return {
            "component_count": 0,
            "largest_ratio": 0.0,
            "second_ratio": 0.0,
            "entropy": 0.0,
            "labels": component_labels,
            "largest_mask": zero_mask,
            "second_mask": zero_mask,
            "areas": [],
        }

    areas = []
    for label in range(1, component_count):
        area = int((component_labels == label).sum())
        areas.append((label, area))
    areas.sort(key=lambda item: item[1], reverse=True)
    probabilities = np.asarray([float(area) / float(total_area) for _label, area in areas], dtype=np.float32)
    entropy = 0.0
    if probabilities.size > 1:
        entropy = float(-(probabilities * np.log(np.clip(probabilities, 1e-8, None))).sum() / np.log(float(probabilities.size)))
    largest_label, largest_area = areas[0]
    largest_mask = component_labels == int(largest_label)
    if len(areas) > 1:
        second_label, second_area = areas[1]
        second_mask = component_labels == int(second_label)
        second_ratio = float(second_area / float(total_area))
    else:
        second_mask = np.zeros_like(binary_mask, dtype=bool)
        second_ratio = 0.0
    return {
        "component_count": fg_connected_components,
        "largest_ratio": float(largest_area / float(total_area)),
        "second_ratio": float(second_ratio),
        "entropy": float(entropy),
        "labels": component_labels,
        "largest_mask": largest_mask,
        "second_mask": second_mask,
        "areas": [{"label": int(label), "area": int(area)} for label, area in areas],
    }


def _peak_indices(profile: np.ndarray, *, min_rel_height: float = 0.35) -> list[int]:
    profile = np.asarray(profile, dtype=np.float32).reshape(-1)
    if profile.size < 3:
        return []
    peak_threshold = float(profile.max()) * float(min_rel_height)
    if peak_threshold <= 0.0:
        return []
    indices = []
    for idx in range(1, profile.size - 1):
        center = float(profile[idx])
        if center < peak_threshold:
            continue
        if center >= float(profile[idx - 1]) and center >= float(profile[idx + 1]):
            indices.append(int(idx))
    return indices


def _render_gap_maps(visible_mask: np.ndarray, fg_mask: np.ndarray) -> tuple[np.ndarray, np.ndarray]:
    visible_mask = np.asarray(visible_mask, dtype=bool)
    fg_mask = np.asarray(fg_mask, dtype=bool)
    kernel = np.ones((5, 5), dtype=np.uint8)
    closed = cv2.morphologyEx(visible_mask.astype(np.uint8), cv2.MORPH_CLOSE, kernel) > 0
    hole_map = fg_mask & closed & ~visible_mask
    bridge_map = np.zeros_like(visible_mask, dtype=bool)

    for y in range(visible_mask.shape[0]):
        fg_row = fg_mask[y]
        visible_cols = np.flatnonzero(visible_mask[y] & fg_row)
        if visible_cols.size >= 2:
            left = int(visible_cols.min())
            right = int(visible_cols.max()) + 1
            row_gap = fg_row[left:right] & ~visible_mask[y, left:right]
            bridge_map[y, left:right] |= row_gap

    for x in range(visible_mask.shape[1]):
        fg_col = fg_mask[:, x]
        visible_rows = np.flatnonzero(visible_mask[:, x] & fg_col)
        if visible_rows.size >= 2:
            top = int(visible_rows.min())
            bottom = int(visible_rows.max()) + 1
            col_gap = fg_col[top:bottom] & ~visible_mask[top:bottom, x]
            bridge_map[top:bottom, x] |= col_gap

    bridge_map &= fg_mask & ~visible_mask
    return hole_map.astype(bool), bridge_map.astype(bool)


def _component_label_rgb(labels: np.ndarray, fg_mask: np.ndarray) -> np.ndarray:
    labels = np.asarray(labels, dtype=np.int32)
    fg_mask = np.asarray(fg_mask, dtype=bool)
    if labels.size == 0:
        return np.zeros((*fg_mask.shape, 3), dtype=np.float16)
    label_max = int(labels.max())
    base = np.zeros((*labels.shape, 3), dtype=np.float16)
    if label_max > 0:
        scaled = labels.astype(np.float32) / float(label_max)
        base = (_apply_heatmap(np.where(fg_mask, scaled, 0.0)).astype(np.float32) / 255.0).astype(np.float16)
    base[~fg_mask] = 0.0
    return base


def _rank_fg_visible_components(
    component_labels: np.ndarray,
    visible_rgb_mask: np.ndarray,
    support_mass: np.ndarray,
    *,
    primary_mass_weight: float = 0.7,
    primary_area_weight: float = 0.3,
    reference_primary_mask: np.ndarray | None = None,
    reference_visible_mask: np.ndarray | None = None,
    reference_primary_weight: float = 0.0,
    reference_visible_weight: float = 0.0,
) -> dict:
    component_labels = np.asarray(component_labels, dtype=np.int32)
    visible_rgb_mask = np.asarray(visible_rgb_mask, dtype=bool)
    support_mass = np.clip(np.asarray(support_mass, dtype=np.float32), 0.0, None)
    total_visible_area = max(int(visible_rgb_mask.sum()), 1)
    total_visible_mass = max(float((support_mass * visible_rgb_mask.astype(np.float32)).sum()), 1e-8)
    if int(component_labels.max()) <= 0 or total_visible_area <= 0:
        empty_mask = np.zeros_like(visible_rgb_mask, dtype=bool)
        return {
            "components": [],
            "primary_component": None,
            "primary_mask": empty_mask,
            "secondary_mask": empty_mask,
        }

    components = []
    height, width = component_labels.shape
    diag = max(float(np.hypot(height, width)), 1.0)
    reference_primary_mask = np.asarray(reference_primary_mask, dtype=bool) if reference_primary_mask is not None else None
    reference_visible_mask = np.asarray(reference_visible_mask, dtype=bool) if reference_visible_mask is not None else None
    for label in range(1, int(component_labels.max()) + 1):
        mask = component_labels == label
        area = int(mask.sum())
        if area <= 0:
            continue
        mass = float((support_mass * mask.astype(np.float32)).sum())
        ys, xs = np.where(mask)
        centroid_y = float(ys.mean()) if ys.size else 0.0
        centroid_x = float(xs.mean()) if xs.size else 0.0
        visible_area_share = float(area / float(total_visible_area))
        visible_mass_share = float(mass / float(total_visible_mass))
        share_entropy = 0.0
        if visible_mass_share > 1e-8:
            share_entropy = float(-visible_mass_share * math.log(max(visible_mass_share, 1e-8)))
        baseline_primary_overlap = (
            float((mask & reference_primary_mask).sum() / float(area))
            if reference_primary_mask is not None
            else 0.0
        )
        baseline_visible_overlap = (
            float((mask & reference_visible_mask).sum() / float(area))
            if reference_visible_mask is not None
            else 0.0
        )
        primary_score = float(
            primary_mass_weight * visible_mass_share
            + primary_area_weight * visible_area_share
            + reference_primary_weight * baseline_primary_overlap
            + reference_visible_weight * baseline_visible_overlap
        )
        components.append(
            {
                "label": int(label),
                "mask": mask,
                "visible_area_share": visible_area_share,
                "visible_mass_share": visible_mass_share,
                "entropy": share_entropy,
                "baseline_primary_overlap": baseline_primary_overlap,
                "baseline_visible_overlap": baseline_visible_overlap,
                "centroid_y": centroid_y,
                "centroid_x": centroid_x,
                "centroid_norm_y": float(centroid_y / max(height - 1, 1)),
                "centroid_norm_x": float(centroid_x / max(width - 1, 1)),
                "centroid_diag_norm": float(np.hypot(centroid_y, centroid_x) / diag),
                "primary_score": primary_score,
            }
        )
    components.sort(key=lambda item: item["primary_score"], reverse=True)
    for rank, component in enumerate(components):
        component["rank"] = int(rank)
    primary_component = components[0] if components else None
    primary_mask = np.asarray(primary_component["mask"], dtype=bool) if primary_component is not None else np.zeros_like(visible_rgb_mask, dtype=bool)
    secondary_mask = np.zeros_like(visible_rgb_mask, dtype=bool)
    for component in components[1:]:
        secondary_mask |= np.asarray(component["mask"], dtype=bool)
    return {
        "components": components,
        "primary_component": primary_component,
        "primary_mask": primary_mask,
        "secondary_mask": secondary_mask.astype(bool),
    }


def _mask_overlap_ratio(mask_a: np.ndarray, mask_b: np.ndarray) -> float:
    mask_a = np.asarray(mask_a, dtype=bool)
    mask_b = np.asarray(mask_b, dtype=bool)
    denom = max(int(mask_a.sum()), 1)
    return float((mask_a & mask_b).sum() / float(denom))


def _mask_centroid_alignment_score(mask_a: np.ndarray, mask_b: np.ndarray) -> float:
    mask_a = np.asarray(mask_a, dtype=bool)
    mask_b = np.asarray(mask_b, dtype=bool)
    if not mask_a.any() or not mask_b.any():
        return 0.0
    ys_a, xs_a = np.nonzero(mask_a)
    ys_b, xs_b = np.nonzero(mask_b)
    centroid_a = np.asarray([float(ys_a.mean()), float(xs_a.mean())], dtype=np.float32)
    centroid_b = np.asarray([float(ys_b.mean()), float(xs_b.mean())], dtype=np.float32)
    diag = max(float(np.hypot(mask_a.shape[0] - 1, mask_a.shape[1] - 1)), 1.0)
    return float(np.clip(1.0 - np.linalg.norm(centroid_a - centroid_b) / diag, 0.0, 1.0))


def _component_touch_ratio(primary_mask: np.ndarray, comp_mask: np.ndarray, *, dilation_k: int = 5) -> float:
    primary_mask = np.asarray(primary_mask, dtype=np.uint8)
    comp_mask = np.asarray(comp_mask, dtype=bool)
    if not comp_mask.any():
        return 0.0
    kernel_size = max(int(dilation_k), 1)
    if kernel_size % 2 == 0:
        kernel_size += 1
    dilated_primary = cv2.dilate(primary_mask, np.ones((kernel_size, kernel_size), dtype=np.uint8), iterations=1) > 0
    return float((dilated_primary & comp_mask).sum() / float(max(int(comp_mask.sum()), 1)))


def _thin_structure_candidate_map(fg_mask: np.ndarray, *, max_width_px: float = 2.5) -> np.ndarray:
    fg_mask = np.asarray(fg_mask, dtype=bool)
    if not fg_mask.any():
        return np.zeros_like(fg_mask, dtype=bool)
    dist = cv2.distanceTransform(fg_mask.astype(np.uint8), cv2.DIST_L2, 5)
    return (fg_mask & (dist <= float(max_width_px))).astype(bool)


def _distance_to_mask(mask: np.ndarray) -> np.ndarray:
    mask = np.asarray(mask, dtype=bool)
    if not mask.any():
        return np.full(mask.shape, 1e6, dtype=np.float32)
    inv = (~mask).astype(np.uint8)
    return cv2.distanceTransform(inv, cv2.DIST_L2, 5).astype(np.float32)


def _component_rank_overlay_rgb(
    ranked_components: dict,
    fg_mask: np.ndarray,
    *,
    title_color: tuple[int, int, int] = (255, 255, 255),
) -> np.ndarray:
    fg_mask = np.asarray(fg_mask, dtype=bool)
    overlay = np.zeros((*fg_mask.shape, 3), dtype=np.uint8)
    overlay[fg_mask] = np.array([18, 18, 18], dtype=np.uint8)
    if fg_mask.any():
        overlay[fg_mask] = np.array([28, 28, 28], dtype=np.uint8)
    ranked = ranked_components.get("components", [])
    palette = [
        np.array([80, 220, 120], dtype=np.uint8),
        np.array([240, 170, 60], dtype=np.uint8),
        np.array([235, 90, 90], dtype=np.uint8),
        np.array([120, 180, 255], dtype=np.uint8),
        np.array([220, 120, 255], dtype=np.uint8),
    ]
    for comp in ranked:
        mask = np.asarray(comp["mask"], dtype=bool)
        overlay[mask] = palette[min(int(comp["rank"]), len(palette) - 1)]
    image = Image.fromarray(overlay)
    draw = ImageDraw.Draw(image)
    font = ImageFont.load_default()
    for comp in ranked:
        x = int(round(comp["centroid_x"]))
        y = int(round(comp["centroid_y"]))
        draw.text((x, y), str(int(comp["rank"])), fill=title_color, font=font)
    return np.asarray(image, dtype=np.uint8)


def _component_touch_graph_overlay(
    ranked_components: dict,
    secondary_scores: dict,
    fg_mask: np.ndarray,
) -> np.ndarray:
    fg_mask = np.asarray(fg_mask, dtype=bool)
    canvas = np.zeros((*fg_mask.shape, 3), dtype=np.uint8)
    canvas[fg_mask] = np.array([24, 24, 24], dtype=np.uint8)
    primary_mask = np.asarray(ranked_components.get("primary_mask", np.zeros_like(fg_mask)), dtype=bool)
    canvas[primary_mask] = np.array([70, 225, 120], dtype=np.uint8)
    image = Image.fromarray(canvas)
    draw = ImageDraw.Draw(image)
    font = ImageFont.load_default()
    primary = ranked_components.get("primary_component")
    if primary is not None:
        px = int(round(primary["centroid_x"]))
        py = int(round(primary["centroid_y"]))
        draw.ellipse((px - 3, py - 3, px + 3, py + 3), fill=(255, 255, 255))
        for comp in ranked_components.get("components", [])[1:]:
            score = secondary_scores.get(int(comp["label"]), {})
            cx = int(round(comp["centroid_x"]))
            cy = int(round(comp["centroid_y"]))
            touching = bool(score.get("touching_primary", False))
            color = (255, 196, 84) if touching else (255, 96, 164)
            draw.line((px, py, cx, cy), fill=color, width=1)
            draw.ellipse((cx - 2, cy - 2, cx + 2, cy + 2), fill=color)
            draw.text((cx + 2, cy + 2), str(int(comp["rank"])), fill=(255, 255, 255), font=font)
    return np.asarray(image, dtype=np.uint8)


def _topology_partition_overlay_rgb(
    base_image01: np.ndarray,
    fg_mask: np.ndarray,
    *,
    core_map: np.ndarray,
    ring_map: np.ndarray,
    rgb_only_map: np.ndarray,
    alpha_allowed_map: np.ndarray,
) -> np.ndarray:
    base = np.clip(np.asarray(base_image01, dtype=np.float32), 0.0, 1.0).copy()
    fg_mask = np.asarray(fg_mask, dtype=bool)
    core_map = np.clip(np.asarray(core_map, dtype=np.float32), 0.0, 1.0)
    ring_map = np.clip(np.asarray(ring_map, dtype=np.float32), 0.0, 1.0)
    rgb_only_map = np.clip(np.asarray(rgb_only_map, dtype=np.float32), 0.0, 1.0)
    alpha_allowed_map = np.clip(np.asarray(alpha_allowed_map, dtype=np.float32), 0.0, 1.0)
    base[~fg_mask] *= 0.35
    overlay = base.copy()
    overlay[..., 0] = np.clip(overlay[..., 0] + 0.70 * core_map + 0.35 * alpha_allowed_map, 0.0, 1.0)
    overlay[..., 1] = np.clip(overlay[..., 1] + 0.70 * rgb_only_map + 0.30 * ring_map, 0.0, 1.0)
    overlay[..., 2] = np.clip(overlay[..., 2] + 0.70 * ring_map + 0.55 * alpha_allowed_map, 0.0, 1.0)
    return (overlay * 255.0).astype(np.uint8)


def _compute_primary_secondary_conflict_scores(
    ranked_components: dict,
    *,
    duplicate_lobe_mask: np.ndarray,
    multilayer_overlap_mask: np.ndarray,
    bridge_context_map: np.ndarray | None = None,
    hole_map: np.ndarray | None = None,
    baseline_primary_mask: np.ndarray | None = None,
    baseline_visible_mask: np.ndarray | None = None,
    residual_map: np.ndarray | None = None,
    source_top1_mass_map: np.ndarray | None = None,
    source_margin_map: np.ndarray | None = None,
    source_label_smoothness_map: np.ndarray | None = None,
    primary_consistency_weight: float = 0.58,
    secondary_conflict_weight: float = 0.72,
    composition_secondary_penalty: float = 0.66,
    conflict_activation_floor: float = 0.24,
    composition_choice_gamma: float = 0.90,
) -> dict:
    components = ranked_components.get("components", [])
    primary_component = ranked_components.get("primary_component")
    shape = np.asarray(duplicate_lobe_mask, dtype=np.float32).shape
    zero_map = np.zeros(shape, dtype=np.float32)
    if primary_component is None or not components:
        return {
            "scores": {},
            "primary_consistency_score_map": zero_map.copy(),
            "secondary_conflict_score_map": zero_map.copy(),
            "composition_conflict_map": zero_map.copy(),
            "primary_preferred_composition_map": zero_map.copy(),
            "secondary_penalty_map": zero_map.copy(),
            "composition_choice_map": zero_map.copy(),
            "composition_rule_delta_map": zero_map.copy(),
        }
    primary_mask = np.asarray(primary_component["mask"], dtype=bool)
    distance_to_primary = _distance_to_mask(primary_mask)
    duplicate_lobe_mask = np.asarray(duplicate_lobe_mask, dtype=bool)
    multilayer_overlap_mask = np.asarray(multilayer_overlap_mask, dtype=bool)
    bridge_context_map = np.asarray(bridge_context_map, dtype=bool) if bridge_context_map is not None else np.zeros(shape, dtype=bool)
    hole_map = np.asarray(hole_map, dtype=bool) if hole_map is not None else np.zeros(shape, dtype=bool)
    baseline_primary_mask = np.asarray(baseline_primary_mask, dtype=bool) if baseline_primary_mask is not None else None
    baseline_visible_mask = np.asarray(baseline_visible_mask, dtype=bool) if baseline_visible_mask is not None else None
    residual_map = np.asarray(residual_map, dtype=np.float32) if residual_map is not None else zero_map.copy()
    source_top1_mass_map = np.asarray(source_top1_mass_map, dtype=np.float32) if source_top1_mass_map is not None else zero_map.copy()
    source_margin_map = np.asarray(source_margin_map, dtype=np.float32) if source_margin_map is not None else zero_map.copy()
    source_label_smoothness_map = (
        np.asarray(source_label_smoothness_map, dtype=np.float32)
        if source_label_smoothness_map is not None
        else zero_map.copy()
    )
    residual_norm = residual_map / max(float(residual_map.max()), 1e-6)
    distance_norm = np.clip(distance_to_primary / max(float(np.hypot(*shape)), 1.0), 0.0, 1.0)
    scores: dict[int, dict] = {}
    primary_consistency_map = zero_map.copy()
    secondary_conflict_map = zero_map.copy()
    composition_conflict_map = zero_map.copy()
    primary_preferred_map = zero_map.copy()
    secondary_penalty_map = zero_map.copy()
    composition_choice_map = zero_map.copy()
    for component in components[1:]:
        label = int(component["label"])
        comp_mask = np.asarray(component["mask"], dtype=bool)
        if not comp_mask.any():
            continue
        comp_area = max(int(comp_mask.sum()), 1)
        duplicate_ratio = float((duplicate_lobe_mask & comp_mask).sum() / float(comp_area))
        overlap_ratio = float((multilayer_overlap_mask & comp_mask).sum() / float(comp_area))
        bridge_ratio = float((bridge_context_map & comp_mask).sum() / float(comp_area))
        hole_ratio = float((hole_map & comp_mask).sum() / float(comp_area))
        baseline_primary_overlap = _mask_overlap_ratio(comp_mask, baseline_primary_mask) if baseline_primary_mask is not None else float(component.get("baseline_primary_overlap", 0.0))
        baseline_visible_overlap = _mask_overlap_ratio(comp_mask, baseline_visible_mask) if baseline_visible_mask is not None else float(component.get("baseline_visible_overlap", 0.0))
        touch_ratio = _component_touch_ratio(primary_mask.astype(np.uint8), comp_mask, dilation_k=7)
        proximity_score = float(np.clip(1.0 - float(distance_norm[comp_mask].mean()), 0.0, 1.0))
        dominance_mean = float(np.clip(float(source_top1_mass_map[comp_mask].mean()), 0.0, 1.0))
        margin_mean = float(np.clip(float(source_margin_map[comp_mask].mean()), 0.0, 1.0))
        smoothness_mean = float(np.clip(float(source_label_smoothness_map[comp_mask].mean()), 0.0, 1.0))
        residual_score = float(np.clip(float(residual_norm[comp_mask].mean()), 0.0, 1.0))
        entropy_scaled = float(np.clip(float(component["entropy"]) * 12.0, 0.0, 1.0))
        continuity_score = float(np.clip(1.0 - 0.60 * bridge_ratio - 0.40 * hole_ratio, 0.0, 1.0))
        primary_consistency_score = float(
            np.clip(
                0.20 * proximity_score
                + 0.20 * margin_mean
                + 0.16 * smoothness_mean
                + 0.14 * baseline_primary_overlap
                + 0.14 * touch_ratio
                + 0.10 * dominance_mean
                + 0.06 * continuity_score,
                0.0,
                1.0,
            )
        )
        secondary_conflict_score = float(
            np.clip(
                0.22 * duplicate_ratio
                + 0.20 * overlap_ratio
                + 0.18 * residual_score
                + 0.12 * baseline_visible_overlap
                + 0.12 * entropy_scaled
                + 0.08 * (1.0 - baseline_primary_overlap)
                + 0.08 * (1.0 - smoothness_mean),
                0.0,
                1.0,
            )
        )
        conflict_score = float(np.clip((primary_consistency_score ** 0.75) * (secondary_conflict_score ** 0.75), 0.0, 1.0))
        penalty_score = float(
            np.clip(
                primary_consistency_weight * primary_consistency_score
                + secondary_conflict_weight * secondary_conflict_score
                + composition_secondary_penalty * conflict_score,
                0.0,
                1.0,
            )
        )
        choice_strength = float(
            np.clip(
                (penalty_score - conflict_activation_floor) / max(1.0 - conflict_activation_floor, 1e-6),
                0.0,
                1.0,
            )
        )
        if composition_choice_gamma > 0.0:
            choice_strength = float(np.clip(choice_strength, 0.0, 1.0) ** max(composition_choice_gamma, 1e-6))
        primary_consistency_map[comp_mask] = np.maximum(primary_consistency_map[comp_mask], np.float32(primary_consistency_score))
        secondary_conflict_map[comp_mask] = np.maximum(secondary_conflict_map[comp_mask], np.float32(secondary_conflict_score))
        composition_conflict_map[comp_mask] = np.maximum(composition_conflict_map[comp_mask], np.float32(conflict_score))
        primary_preferred_map[comp_mask] = np.maximum(primary_preferred_map[comp_mask], np.float32(choice_strength))
        secondary_penalty_map[comp_mask] = np.maximum(secondary_penalty_map[comp_mask], np.float32(penalty_score))
        composition_choice_map[comp_mask] = np.maximum(composition_choice_map[comp_mask], np.float32(choice_strength))
        scores[label] = {
            "primary_consistency_score": float(primary_consistency_score),
            "secondary_conflict_score": float(secondary_conflict_score),
            "composition_penalty_score": float(penalty_score),
            "baseline_visible_overlap": float(baseline_visible_overlap),
            "baseline_primary_overlap": float(baseline_primary_overlap),
            "resolved_to_primary_fraction": float(choice_strength),
            "resolved_to_secondary_fraction": float(1.0 - choice_strength),
            "final_composition_partition": "primary_preferred_conflict_region" if choice_strength >= float(conflict_activation_floor) else "secondary_retained_low_conflict",
            "touch_ratio_to_primary": float(touch_ratio),
            "bridge_context_ratio": float(bridge_ratio),
            "hole_ratio": float(hole_ratio),
        }
    return {
        "scores": scores,
        "primary_consistency_score_map": np.clip(primary_consistency_map, 0.0, 1.0).astype(np.float32),
        "secondary_conflict_score_map": np.clip(secondary_conflict_map, 0.0, 1.0).astype(np.float32),
        "composition_conflict_map": np.clip(composition_conflict_map, 0.0, 1.0).astype(np.float32),
        "primary_preferred_composition_map": np.clip(primary_preferred_map, 0.0, 1.0).astype(np.float32),
        "secondary_penalty_map": np.clip(secondary_penalty_map, 0.0, 1.0).astype(np.float32),
        "composition_choice_map": np.clip(composition_choice_map, 0.0, 1.0).astype(np.float32),
        "composition_rule_delta_map": zero_map.copy(),
    }


def _build_primary_reference_image(
    inherited_image: np.ndarray,
    inherited_baseline_image: np.ndarray,
    primary_mask: np.ndarray,
    *,
    bridge_context_map: np.ndarray | None = None,
    hole_map: np.ndarray | None = None,
    bridge_safe_mix: float = 0.84,
    hole_guard_mix: float = 0.46,
    sigma: float = 3.0,
) -> np.ndarray:
    inherited_image = np.asarray(inherited_image, dtype=np.float32)
    inherited_baseline_image = np.asarray(inherited_baseline_image, dtype=np.float32)
    primary_mask = np.asarray(primary_mask, dtype=np.float32)
    sigma = max(float(sigma), 1.0)
    primary_rgb = inherited_image * primary_mask[..., None]
    blur_rgb = cv2.GaussianBlur(primary_rgb, (0, 0), sigma)
    blur_mask = cv2.GaussianBlur(primary_mask, (0, 0), sigma)
    primary_ref = np.where(
        blur_mask[..., None] > 1e-6,
        blur_rgb / np.maximum(blur_mask[..., None], 1e-6),
        inherited_baseline_image,
    )
    bridge_context_map = np.asarray(bridge_context_map, dtype=np.float32) if bridge_context_map is not None else np.zeros(primary_mask.shape, dtype=np.float32)
    hole_map = np.asarray(hole_map, dtype=np.float32) if hole_map is not None else np.zeros(primary_mask.shape, dtype=np.float32)
    safety = np.clip(1.0 - bridge_safe_mix * bridge_context_map - hole_guard_mix * hole_map, 0.05, 1.0)
    primary_ref = np.clip(primary_ref * safety[..., None] + inherited_baseline_image * (1.0 - safety[..., None]), 0.0, 1.0)
    return primary_ref.astype(np.float32)


def _decompose_rehydrated_operator_contributions(
    *,
    inherited_image: np.ndarray,
    ranked_components: dict,
    parent_artifact: dict,
    baseline_artifact: dict,
    fg_mask: np.ndarray,
    raw_support_weight: np.ndarray,
    target01: np.ndarray,
    source_top1_mass_map: np.ndarray,
    source_margin_map: np.ndarray,
    source_label_smoothness_map: np.ndarray,
    proxy_config: dict,
) -> dict:
    fg_mask = np.asarray(fg_mask, dtype=bool)
    raw_support_weight = np.asarray(raw_support_weight, dtype=np.float32)
    shape = raw_support_weight.shape
    primary_mask = np.asarray(ranked_components.get("primary_mask", np.zeros_like(fg_mask)), dtype=bool)
    secondary_mask = np.asarray(ranked_components.get("secondary_mask", np.zeros_like(fg_mask)), dtype=bool)
    duplicate_map = np.asarray(parent_artifact["duplicate_lobe_mask"], dtype=np.float32)
    overlap_map = np.asarray(parent_artifact["multilayer_overlap_mask"], dtype=np.float32)
    bridge_map = np.asarray(parent_artifact["bridge_map"], dtype=np.float32)
    hole_map = np.asarray(parent_artifact["hole_map"], dtype=np.float32)
    thin_structure_map = _thin_structure_candidate_map(primary_mask | secondary_mask).astype(np.float32)
    baseline_primary_mask = np.asarray(baseline_artifact["largest_mask"], dtype=bool)
    baseline_visible_mask = np.asarray(baseline_artifact["visible_mask"], dtype=bool)
    residual_map = np.abs(np.asarray(inherited_image, dtype=np.float32) - np.asarray(target01, dtype=np.float32)).mean(axis=2)
    residual_norm = residual_map / max(float(residual_map.max()), 1e-6)
    conflict_scores = _compute_primary_secondary_conflict_scores(
        ranked_components,
        duplicate_lobe_mask=np.asarray(parent_artifact["duplicate_lobe_mask"], dtype=bool),
        multilayer_overlap_mask=np.asarray(parent_artifact["multilayer_overlap_mask"], dtype=bool),
        bridge_context_map=np.asarray(parent_artifact["bridge_map"], dtype=bool),
        hole_map=np.asarray(parent_artifact["hole_map"], dtype=bool),
        baseline_primary_mask=baseline_primary_mask,
        baseline_visible_mask=baseline_visible_mask,
        residual_map=residual_norm,
        source_top1_mass_map=source_top1_mass_map,
        source_margin_map=source_margin_map,
        source_label_smoothness_map=source_label_smoothness_map,
        primary_consistency_weight=float(proxy_config.get("primary_consistency_weight", 0.62)),
        secondary_conflict_weight=float(proxy_config.get("secondary_conflict_weight", 0.78)),
        composition_secondary_penalty=float(proxy_config.get("composition_secondary_penalty", 0.78)),
        conflict_activation_floor=float(proxy_config.get("operator_conflict_activation_floor", 0.10)),
        composition_choice_gamma=float(proxy_config.get("composition_choice_gamma", 0.80)),
    )
    primary_consistency_map = np.asarray(conflict_scores["primary_consistency_score_map"], dtype=np.float32)
    secondary_conflict_map = np.asarray(conflict_scores["secondary_conflict_score_map"], dtype=np.float32)
    composition_conflict_map = np.asarray(conflict_scores["composition_conflict_map"], dtype=np.float32)
    baseline_primary_overlap_map = np.zeros_like(raw_support_weight, dtype=np.float32)
    baseline_visible_overlap_map = np.zeros_like(raw_support_weight, dtype=np.float32)
    touch_ratio_map = np.zeros_like(raw_support_weight, dtype=np.float32)
    component_merge_candidate_map = np.zeros_like(raw_support_weight, dtype=np.float32)
    component_scores: dict[int, dict] = {}
    structural_continuity_map = (
        fg_mask
        & (
            (bridge_map >= float(proxy_config.get("bridge_core_threshold", 0.16)))
            | (hole_map >= float(proxy_config.get("hole_core_threshold", 0.12)))
            | (thin_structure_map >= float(proxy_config.get("thin_core_threshold", 0.32)))
        )
    )
    for component in ranked_components.get("components", [])[1:]:
        label = int(component["label"])
        comp_mask = np.asarray(component["mask"], dtype=bool)
        if not comp_mask.any():
            continue
        comp_area = max(int(comp_mask.sum()), 1)
        score_info = conflict_scores["scores"].get(label, {})
        baseline_primary_overlap = float(score_info.get("baseline_primary_overlap", component.get("baseline_primary_overlap", 0.0)))
        baseline_visible_overlap = float(score_info.get("baseline_visible_overlap", component.get("baseline_visible_overlap", 0.0)))
        touch_ratio = float(score_info.get("touch_ratio_to_primary", 0.0))
        bridge_ratio = float(score_info.get("bridge_context_ratio", 0.0))
        hole_ratio = float(score_info.get("hole_ratio", 0.0))
        duplicate_ratio = float((duplicate_map[comp_mask] > 0.0).mean())
        overlap_ratio = float((overlap_map[comp_mask] > 0.0).mean())
        thin_ratio = float(thin_structure_map[comp_mask].mean())
        residual_score = float(residual_norm[comp_mask].mean())
        continuity_score = float(np.clip(1.0 - 0.58 * bridge_ratio - 0.42 * hole_ratio - 0.46 * thin_ratio, 0.0, 1.0))
        merge_candidate_score = float(
            np.clip(
                0.26 * float(score_info.get("secondary_conflict_score", 0.0))
                + 0.20 * duplicate_ratio
                + 0.16 * overlap_ratio
                + 0.12 * max(baseline_visible_overlap - baseline_primary_overlap, 0.0)
                + 0.14 * residual_score
                + 0.12 * max(1.0 - continuity_score, 0.0),
                0.0,
                1.0,
            )
        )
        baseline_primary_overlap_map[comp_mask] = baseline_primary_overlap
        baseline_visible_overlap_map[comp_mask] = baseline_visible_overlap
        touch_ratio_map[comp_mask] = touch_ratio
        component_merge_candidate_map[comp_mask] = np.maximum(
            component_merge_candidate_map[comp_mask],
            np.float32(merge_candidate_score if merge_candidate_score >= float(proxy_config.get("operator_merge_gain_floor", 0.14)) else 0.0),
        )
        component_scores[label] = {
            **score_info,
            "baseline_primary_overlap": baseline_primary_overlap,
            "baseline_visible_overlap": baseline_visible_overlap,
            "touch_ratio_to_primary": touch_ratio,
            "bridge_context_ratio": bridge_ratio,
            "hole_ratio": hole_ratio,
            "thin_structure_ratio": thin_ratio,
            "duplicate_ratio": duplicate_ratio,
            "overlap_ratio": overlap_ratio,
            "residual_score": residual_score,
            "continuity_score": continuity_score,
            "merge_candidate_score": merge_candidate_score,
        }
    continuity_protected_map = structural_continuity_map | (
        fg_mask
        & (baseline_primary_overlap_map >= float(proxy_config.get("operator_continuity_overlap_floor", 0.42)))
        & (touch_ratio_map >= float(proxy_config.get("operator_continuity_touch_floor", 0.18)))
        & (component_merge_candidate_map < float(proxy_config.get("operator_continuity_merge_ceiling", 0.26)))
    )
    continuity_dilate_px = max(int(proxy_config.get("continuity_protected_dilate_px", 1)), 0)
    if continuity_dilate_px > 0:
        kernel = np.ones((continuity_dilate_px * 2 + 1, continuity_dilate_px * 2 + 1), dtype=np.uint8)
        continuity_protected_map = (cv2.dilate(continuity_protected_map.astype(np.uint8), kernel, iterations=1) > 0) & fg_mask
    primary_contribution_map = np.clip(
        fg_mask.astype(np.float32)
        * (
            0.42 * primary_mask.astype(np.float32)
            + 0.24 * primary_consistency_map
            + 0.16 * baseline_primary_overlap_map
            + 0.10 * np.clip(source_margin_map, 0.0, 1.0)
            + 0.08 * np.clip(source_label_smoothness_map, 0.0, 1.0)
        ),
        0.0,
        1.0,
    ).astype(np.float32)
    secondary_contribution_map = np.clip(
        fg_mask.astype(np.float32)
        * (
            0.34 * secondary_mask.astype(np.float32)
            + 0.24 * secondary_conflict_map
            + 0.14 * duplicate_map
            + 0.10 * overlap_map
            + 0.10 * np.clip(source_top1_mass_map, 0.0, 1.0)
            + 0.08 * residual_norm
        ),
        0.0,
        1.0,
    ).astype(np.float32)
    conflict_resolution_map = np.clip(
        fg_mask.astype(np.float32)
        * (1.0 - continuity_protected_map.astype(np.float32))
        * (
            0.42 * composition_conflict_map
            + 0.22 * component_merge_candidate_map
            + 0.18 * duplicate_map
            + 0.10 * overlap_map
            + 0.08 * np.clip(np.abs(primary_contribution_map - secondary_contribution_map), 0.0, 1.0)
        ),
        0.0,
        1.0,
    ).astype(np.float32)
    return {
        "component_scores": component_scores,
        "conflict_scores": conflict_scores,
        "primary_mask": primary_mask,
        "secondary_mask": secondary_mask,
        "primary_contribution_map": primary_contribution_map,
        "secondary_contribution_map": secondary_contribution_map,
        "conflict_resolution_map": conflict_resolution_map,
        "continuity_bypass_map": continuity_protected_map.astype(np.float32),
        "component_merge_candidate_map": component_merge_candidate_map.astype(np.float32),
        "baseline_primary_overlap_map": baseline_primary_overlap_map.astype(np.float32),
        "baseline_visible_overlap_map": baseline_visible_overlap_map.astype(np.float32),
        "touch_ratio_map": touch_ratio_map.astype(np.float32),
        "thin_structure_map": thin_structure_map.astype(np.float32),
        "duplicate_map": duplicate_map.astype(np.float32),
        "overlap_map": overlap_map.astype(np.float32),
        "bridge_map": bridge_map.astype(np.float32),
        "hole_map": hole_map.astype(np.float32),
        "primary_consistency_map": primary_consistency_map.astype(np.float32),
        "secondary_conflict_map": secondary_conflict_map.astype(np.float32),
    }


