            ("Gap closure", _apply_heatmap(post_merge_component_gap_closure_map).astype(np.float32) / 255.0),
            ("Adjacency veto", _apply_heatmap(post_merge_component_adjacency_veto_map).astype(np.float32) / 255.0),
