    inherited_alpha = np.clip(np.asarray(inherited_alpha, dtype=np.float32), 0.0, 1.0)
    inherited_baseline_image = np.clip(np.asarray(inherited_baseline_image, dtype=np.float32), 0.0, 1.0)
