            * np.clip(1.0 - 0.58 * hard_anchor_peak_residual_veto_map, 0.0, 1.0)
            * np.clip(1.0 - 0.34 * hard_anchor_peak_residual_guard_map, 0.0, 1.0),
            0.0,
