                    + 0.36 * hard_anchor_peak_residual_binding_map
                    + 0.24 * hard_anchor_peak_residual_activation_map
                    + 0.16 * hard_anchor_breakout_alignment_map
                    + 0.12 * hard_anchor_peak_rebound_focus_map
