                                            + 0.24
                                            * hard_anchor_peak_residual_overlap_gain_density_landing_collapse_binding_map
                                            + 0.22
                                            * hard_anchor_peak_residual_overlap_gain_density_landing_collapse_contract_map
                                            + 0.18 * post_merge_component_adjacency_contract_map
                                            + 0.10 * post_merge_component_gap_closure_map
                                            + 0.08
                                            * hard_anchor_peak_residual_overlap_gain_density_landing_collapse_connectivity_alignment_map
